import{_ as e,o as a,c as n,ae as o}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Manage Payments","description":"","frontmatter":{"title":"Manage Payments","slug":"manage-payments"},"headers":[],"relativePath":"account-hub/manage-payments.md","filePath":"account-hub/manage-payments.md"}'),i={name:"account-hub/manage-payments.md"};function l(r,t,s,d,c,h){return a(),n("div",null,[...t[0]||(t[0]=[o('<p>The <strong>Billing</strong> tab is where you can see your payment information and make changes if you need to.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Please note that this article explains the <a href="./branch-dashboard-overview.html">legacy Branch experience</a> for managing payments, which is slated for deprecation.</p><p>In the <a href="./new-branch-overview.html">new version of Branch</a>, attribution windows are configured under <strong>Account</strong> → <a href="./billing-payments-new.html"><strong>Billing</strong></a>.</p></div><h3 id="add-new-payment-method" tabindex="-1">Add new payment method <a class="header-anchor" href="#add-new-payment-method" aria-label="Permalink to &quot;Add new payment method&quot;">​</a></h3><p>To add a new payment method:</p><ol><li>Go to <strong>Account Settings</strong> on the navigation menu.</li><li>Navigate to the <strong>Billing</strong> tab.</li><li>Click <strong>New Payment Method</strong>.</li><li>Complete the fields to add a new credit card to your account, and click <strong>Submit</strong>.</li></ol><div class="info custom-block"><p class="custom-block-title">Note</p><p>You will also be prompted to input a payment method if any of the following scenarios occur:</p><ul><li>Your account was on a trial and that trial has expired.</li><li>Your account is reaching your MAU usage limits.</li><li>Your default payment method has been declined.</li><li>Your account is on an Enterprise plan and has delinquent payments.</li></ul></div><h3 id="change-default-payment-method" tabindex="-1">Change default payment method <a class="header-anchor" href="#change-default-payment-method" aria-label="Permalink to &quot;Change default payment method&quot;">​</a></h3><p>To change your default payment method:</p><ol><li>Go to <strong>Account Settings</strong> on the navigation menu.</li><li>Navigate to the <strong>Billing</strong> tab.</li><li>Click the three dots button next to the payment method you want to make the default.</li><li>Click <strong>Set as Default</strong> and click <strong>Yes</strong> to verify.</li></ol><h3 id="delete-payment-method" tabindex="-1">Delete payment method <a class="header-anchor" href="#delete-payment-method" aria-label="Permalink to &quot;Delete payment method&quot;">​</a></h3><p>To delete a payment method:</p><ol><li>Go to <strong>Account Settings</strong> on the navigation menu.</li><li>Navigate to the <strong>Billing</strong> tab.</li><li>Click the three dots button next to the payment method you want to delete.</li><li>Click <strong>Delete Card</strong> and click <strong>Yes, Delete</strong> to verify.</li></ol>',12)])])}const p=e(i,[["render",l]]);export{g as __pageData,p as default};
